module RefModule(
	input clk,
	input enable,
	input load,
	input reset,
	input [9:0] load_value,
	output reg [9:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset)
		q <= 10'b0;
	else if (load)
		q <= load_value;
	else if (enable)
		q <= q + 1;
end
endmodule
